def series(pts, kind, label):
    return {"label": label, "kind": kind, "x": [p[0] for p in pts], "y": [p[1] for p in pts]}


def main():
    data = {
        "source": ("Couppey et al. 2024 (NRV) Fig 9A; in-vivo Nannini & Horch 1991 (NH); "
                   "digitized by user, 2026-06-20. Intensity sweep only."),
        "panel_a": {
            "xlabel": "Current (µA)", "ylabel": "Recruitment (norm.)",
            "NH1991_50us": series(A_NH_50, "dots", "50 µs — NH 1991"),
            "NH1991_20us": series(A_NH_20, "dots", "20 µs — NH 1991"),
            "NRV_50us": series(A_NRV_50, "line", "50 µs — NRV"),
            "NRV_20us": series(A_NRV_20, "line", "20 µs — NRV"),
        },
    }
    OUT.write_text(json.dumps(data, indent=2))
    na = sum(len(v["x"]) for v in data["panel_a"].values() if isinstance(v, dict) and "x" in v)
    print(f"wrote {OUT.name}: panel A {na} pts (4 series); panel B removed")


if __name__ == "__main__":
    main()
